# Generated by Codex for Pyomo DoE PDE diffusion diagnostic execution
"""
Execute PDE diffusion diagnostics across discretizations and environments,
collect JSON outputs, compute medians and derived metrics, and summarize results.
"""

from __future__ import annotations

import json
import subprocess
from datetime import datetime
from pathlib import Path
from typing import Dict, List, Tuple

import numpy as np
import pandas as pd


ROOT_DIR = Path("/Users/snarasi2/projects/Pyomo_DoE_CRC")
OUT_DIR = ROOT_DIR / "out"
TIMESTAMP = datetime.now().strftime("%Y%m%d_%H%M%S")
RUN_DIR = OUT_DIR / f"analysis_execution_{TIMESTAMP}"
CENTRAL_DIR = RUN_DIR / "central_fd"
SYMBOLIC_DIR = RUN_DIR / "symbolic"

DISCRETIZATIONS = [
    (2, 2),
    (5, 10),
    (10, 20),
    (25, 40),
    (50, 75),
]

BASELINE_METRICS = [
    "doe_build_time",
    "doe_init_time",
    "doe_solve_time",
    "doe_wall_time",
    "ipopt_iters",
    "obj_eval",
    "grad_eval",
    "eq_con_eval",
    "eq_jac_eval",
    "hess_eval",
    "ipopt_cpu_wo_feval",
    "ipopt_cpu_nlp_feval",
    "ipopt_exit",
]


def ensure_output_dirs() -> None:
    """
    Create output directories for this execution run.
    """
    CENTRAL_DIR.mkdir(parents=True, exist_ok=True)
    SYMBOLIC_DIR.mkdir(parents=True, exist_ok=True)


def run_command(cmd: List[str]) -> None:
    """
    Run a subprocess command and raise on failure.

    Parameters:
        cmd: Command list to execute.
    """
    subprocess.run(cmd, check=True)


def confirm_environment(env_name: str) -> None:
    """
    Print sys.executable and pyomo.__version__ for the given conda environment.

    Parameters:
        env_name: Conda environment name.
    """
    cmd = [
        "conda",
        "run",
        "-n",
        env_name,
        "python",
        "-c",
        "import sys, pyomo; "
        "print('sys.executable=' + sys.executable); "
        "print('pyomo.__version__=' + str(pyomo.__version__))",
    ]
    run_command(cmd)


def run_helper(
    env_name: str,
    method: str,
    mode: str,
    nfe_x: int,
    nfe_t: int,
    out_json: Path,
    run_dir: Path,
    ipopt_out: Path,
) -> None:
    """
    Invoke the helper script inside a conda environment.

    Parameters:
        env_name: Conda environment name.
        method: "central" or "symbolic".
        mode: "baseline", "no_solve", or "solve_twice".
        nfe_x: Spatial discretization.
        nfe_t: Temporal discretization.
        out_json: Output JSON path.
        run_dir: Run directory for IPOPT output.
        ipopt_out: IPOPT output file path.
    """
    cmd = [
        "conda",
        "run",
        "-n",
        env_name,
        "python",
        str(ROOT_DIR / "pde_doe_execution_helper.py"),
        "--method",
        method,
        "--mode",
        mode,
        "--nfe_x",
        str(nfe_x),
        "--nfe_t",
        str(nfe_t),
        "--out_json",
        str(out_json),
        "--run_dir",
        str(run_dir),
        "--ipopt_out",
        str(ipopt_out),
    ]
    run_command(cmd)


def collect_jsons(folder: Path) -> List[Dict[str, object]]:
    """
    Load all JSON files within a folder.

    Parameters:
        folder: Directory containing JSON outputs.

    Returns:
        List of dictionaries.
    """
    records: List[Dict[str, object]] = []
    for path in sorted(folder.glob("*.json")):
        with path.open("r", encoding="utf-8") as handle:
            record = json.load(handle)
        record["source_file"] = path.name
        records.append(record)
    return records


def compute_baseline_medians(records: List[Dict[str, object]]) -> pd.DataFrame:
    """
    Compute median baseline metrics per method and discretization.

    Parameters:
        records: List of baseline run records.

    Returns:
        Dataframe of median metrics.
    """
    df = pd.DataFrame(records)
    numeric_cols = [c for c in BASELINE_METRICS if c != "ipopt_exit"]
    for col in numeric_cols:
        df[col] = pd.to_numeric(df[col], errors="coerce")
    grouped = df.groupby(["method", "nfe_x", "nfe_t"], sort=False)
    median_df = grouped[numeric_cols].median().reset_index()
    exit_df = grouped["ipopt_exit"].agg(lambda x: x.iloc[0]).reset_index()
    result = pd.merge(median_df, exit_df, on=["method", "nfe_x", "nfe_t"], how="left")
    return result


def compute_derived_metrics(baseline_df: pd.DataFrame) -> pd.DataFrame:
    """
    Compute derived metrics and symbolic/central ratios.

    Parameters:
        baseline_df: Dataframe of baseline medians.

    Returns:
        Dataframe of derived metrics and ratios per discretization.
    """
    df = baseline_df.copy()
    df["stage_share_build"] = df["doe_build_time"] / df["doe_wall_time"]
    df["stage_share_init"] = df["doe_init_time"] / df["doe_wall_time"]
    df["stage_share_solve"] = df["doe_solve_time"] / df["doe_wall_time"]
    df["solve_time_per_iter"] = np.where(
        df["ipopt_iters"] > 0, df["doe_solve_time"] / df["ipopt_iters"], np.nan
    )
    df["overhead_time"] = df["doe_wall_time"] - df["doe_solve_time"]

    def safe_div(numerator: float, denominator: float) -> float:
        if denominator in (None, 0) or pd.isna(denominator):
            return np.nan
        return numerator / denominator

    ratio_rows = []
    for (nfe_x, nfe_t), group in df.groupby(["nfe_x", "nfe_t"], sort=False):
        central = group[group["method"] == "central"]
        symbolic = group[group["method"] == "symbolic"]
        if central.empty or symbolic.empty:
            continue
        c = central.iloc[0]
        s = symbolic.iloc[0]
        ratio_rows.append(
            {
                "nfe_x": nfe_x,
                "nfe_t": nfe_t,
                "build_ratio": safe_div(s["doe_build_time"], c["doe_build_time"]),
                "init_ratio": safe_div(s["doe_init_time"], c["doe_init_time"]),
                "solve_ratio": safe_div(s["doe_solve_time"], c["doe_solve_time"]),
                "wall_ratio": safe_div(s["doe_wall_time"], c["doe_wall_time"]),
                "solve_time_per_iter_ratio": safe_div(
                    s["solve_time_per_iter"], c["solve_time_per_iter"]
                ),
            }
        )
    ratio_df = pd.DataFrame(ratio_rows)
    merged = pd.merge(df, ratio_df, on=["nfe_x", "nfe_t"], how="left")
    return merged


def write_interpretation(
    baseline_df: pd.DataFrame,
    derived_df: pd.DataFrame,
    output_path: Path,
) -> None:
    """
    Write the diagnostic interpretation file.

    Parameters:
        baseline_df: Baseline median dataframe.
        derived_df: Derived metrics dataframe.
        output_path: Output text file path.
    """
    lines: List[str] = []
    ordered = baseline_df.sort_values(by=["nfe_x", "nfe_t", "method"], kind="stable")
    largest = ordered[(ordered["nfe_x"] == 50) & (ordered["nfe_t"] == 75)]

    lines.append("Diagnostic interpretation (quantitative)")
    lines.append("")
    lines.append("Largest discretization (nfe_x=50, nfe_t=75):")
    for _, row in largest.iterrows():
        lines.append(
            f"{row['method']} build={row['doe_build_time']}, "
            f"init={row['doe_init_time']}, solve={row['doe_solve_time']}, "
            f"wall={row['doe_wall_time']}, ipopt_iters={row['ipopt_iters']}"
        )
    lines.append("")

    def trend_increasing(series: List[float]) -> bool:
        return all(x2 >= x1 for x1, x2 in zip(series, series[1:]))

    for method in ["central", "symbolic"]:
        subset = derived_df[derived_df["method"] == method].sort_values(
            by=["nfe_x", "nfe_t"], kind="stable"
        )
        iters = subset["ipopt_iters"].tolist()
        solve_pi = subset["solve_time_per_iter"].tolist()
        lines.append(
            f"{method} ipopt_iters increasing with refinement: {trend_increasing(iters)}"
        )
        lines.append(
            f"{method} solve_time_per_iter increasing with refinement: {trend_increasing(solve_pi)}"
        )

    largest_central = derived_df[
        (derived_df["method"] == "central")
        & (derived_df["nfe_x"] == 50)
        & (derived_df["nfe_t"] == 75)
    ]
    if not largest_central.empty:
        row = largest_central.iloc[0]
        dominant = max(
            [("build", row["stage_share_build"]), ("init", row["stage_share_init"]), ("solve", row["stage_share_solve"])],
            key=lambda x: x[1],
        )[0]
        lines.append(f"Dominant wall-time stage (central, largest): {dominant}")

    largest_ratios = derived_df[
        (derived_df["nfe_x"] == 50) & (derived_df["nfe_t"] == 75)
    ]
    if not largest_ratios.empty:
        ratio_row = largest_ratios.iloc[0]
        lines.append(
            f"Symbolic/Central ratios at largest: build={ratio_row['build_ratio']}, "
            f"init={ratio_row['init_ratio']}, solve={ratio_row['solve_ratio']}, "
            f"wall={ratio_row['wall_ratio']}, solve_time_per_iter={ratio_row['solve_time_per_iter_ratio']}"
        )

    cpu_cols = ["ipopt_cpu_wo_feval", "ipopt_cpu_nlp_feval"]
    for metric in cpu_cols:
        central_series = derived_df[derived_df["method"] == "central"].sort_values(
            by=["nfe_x", "nfe_t"], kind="stable"
        )[metric].tolist()
        symbolic_series = derived_df[derived_df["method"] == "symbolic"].sort_values(
            by=["nfe_x", "nfe_t"], kind="stable"
        )[metric].tolist()
        if central_series and symbolic_series:
            central_growth = central_series[-1] / central_series[0]
            symbolic_growth = symbolic_series[-1] / symbolic_series[0]
            faster = "symbolic" if symbolic_growth > central_growth else "central"
            lines.append(
                f"{metric} growth: central={central_growth}, symbolic={symbolic_growth}, faster={faster}"
            )

    lines.append("")
    lines.append("Primary slowdown driver:")
    lines.append("See dominant wall-time stage and symbolic/central ratios above.")
    lines.append("Evidence:")
    lines.append("Largest discretization times and ratios, plus trends in iterations and per-iter time.")
    lines.append("Recommended next step:")
    lines.append("Inspect the dominant stage in profiling or enable solver logs for deeper timing granularity.")

    output_path.write_text("\n".join(lines) + "\n", encoding="utf-8")


def main() -> None:
    """
    Entry point for executing diagnostic runs and aggregations.
    """
    ensure_output_dirs()

    confirm_environment("pyomo")
    confirm_environment("pyomosym")

    baseline_records: List[Dict[str, object]] = []
    no_solve_records: List[Dict[str, object]] = []
    solve_twice_records: List[Dict[str, object]] = []

    for method, env_name, base_dir in [
        ("central", "pyomo", CENTRAL_DIR),
        ("symbolic", "pyomosym", SYMBOLIC_DIR),
    ]:
        baseline_dir = base_dir / "baseline"
        no_solve_dir = base_dir / "no_solve"
        solve_twice_dir = base_dir / "solve_twice"
        baseline_dir.mkdir(parents=True, exist_ok=True)
        no_solve_dir.mkdir(parents=True, exist_ok=True)
        solve_twice_dir.mkdir(parents=True, exist_ok=True)

        for nfe_x, nfe_t in DISCRETIZATIONS:
            for run_idx in range(1, 4):
                out_json = baseline_dir / f"baseline_nfe_x{nfe_x}_nfe_t{nfe_t}_run{run_idx}.json"
                ipopt_out = baseline_dir / f"ipopt_nfe_x{nfe_x}_nfe_t{nfe_t}_run{run_idx}.out"
                run_helper(
                    env_name,
                    method,
                    "baseline",
                    nfe_x,
                    nfe_t,
                    out_json,
                    baseline_dir,
                    ipopt_out,
                )
                with out_json.open("r", encoding="utf-8") as handle:
                    record = json.load(handle)
                record["method"] = method
                baseline_records.append(record)

        nfe_x, nfe_t = DISCRETIZATIONS[-1]
        out_json = no_solve_dir / f"no_solve_nfe_x{nfe_x}_nfe_t{nfe_t}.json"
        ipopt_out = no_solve_dir / f"ipopt_no_solve_nfe_x{nfe_x}_nfe_t{nfe_t}.out"
        run_helper(
            env_name,
            method,
            "no_solve",
            nfe_x,
            nfe_t,
            out_json,
            no_solve_dir,
            ipopt_out,
        )
        no_solve_records.extend(collect_jsons(no_solve_dir))

        out_json = solve_twice_dir / f"solve_twice_nfe_x{nfe_x}_nfe_t{nfe_t}.json"
        ipopt_out = solve_twice_dir / f"ipopt_solve1_nfe_x{nfe_x}_nfe_t{nfe_t}.out"
        run_helper(
            env_name,
            method,
            "solve_twice",
            nfe_x,
            nfe_t,
            out_json,
            solve_twice_dir,
            ipopt_out,
        )
        solve_twice_records.extend(collect_jsons(solve_twice_dir))

    baseline_df = compute_baseline_medians(baseline_records)
    baseline_df.to_csv(RUN_DIR / "baseline_results.csv", index=False)

    pd.DataFrame(no_solve_records).to_csv(RUN_DIR / "no_solve_results.csv", index=False)
    pd.DataFrame(solve_twice_records).to_csv(RUN_DIR / "solve_twice_results.csv", index=False)

    derived_df = compute_derived_metrics(baseline_df)
    derived_df.to_csv(RUN_DIR / "derived_metrics.csv", index=False)

    interpretation_path = RUN_DIR / "diagnostic_interpretation.txt"
    write_interpretation(baseline_df, derived_df, interpretation_path)

    print(f"Wrote outputs to: {RUN_DIR}")


if __name__ == "__main__":
    main()
